Alias.script:
-- ^occ$  ->  toggle Occultist offense on/off
Yso = Yso or {}
Yso.off = Yso.off or {}
Yso.off.oc = Yso.off.oc or {}
if type(Yso.off.oc.toggle) == "function" then
  Yso.off.oc.toggle()
else
  cecho("<red>[YSO]<reset> Offense module not loaded.\n")
end

-- ^occon$ -> force offense ON Yso = Yso or {} Yso.off = Yso.off or {} Yso.off.oc = Yso.off.oc or {} Yso.off.driver = Yso.off.driver or {}
local called = false if type(Yso.off.oc.on) == "function" then local ok = pcall(Yso.off.oc.on) called = (ok == true) elseif type(Yso.off.oc.toggle) == "function" then pcall(Yso.off.oc.toggle, true) called = true elseif type(Yso.off.driver.toggle) == "function" then pcall(Yso.off.driver.toggle, true) called = true end
if not called then cecho("<red>[YSO]<reset> Offense module not loaded.\n") end

-- ^occoff$ -> force offense OFF Yso = Yso or {} Yso.off = Yso.off or {} Yso.off.oc = Yso.off.oc or {} Yso.off.driver = Yso.off.driver or {}
local called = false if type(Yso.off.oc.off) == "function" then local ok = pcall(Yso.off.oc.off) called = (ok == true) elseif type(Yso.off.oc.toggle) == "function" then pcall(Yso.off.oc.toggle, false) called = true elseif type(Yso.off.driver.toggle) == "function" then pcall(Yso.off.driver.toggle, false) called = true end
if not called then cecho("<red>[YSO]<reset> Offense module not loaded.\n") end

-- ^lim$ -> combat mode + Cleanseaura lim route Yso = Yso or {} Yso.occ = Yso.occ or {} Yso.occ.clock = Yso.occ.clock or {}
if Yso.mode and type(Yso.mode.set) == "function" then pcall(Yso.mode.set, "combat", "alias:lim") end
if type(Yso.occ.clock.set_route) == "function" then Yso.occ.clock.set_route("lim") else Yso.occ.clock.cfg = Yso.occ.clock.cfg or {} Yso.occ.clock.cfg.route = "lim" if type(cecho) == "function" then cecho("<dark_orchid>[Occultism] <reset>Cleanseaura route: <yellow>lim<reset>\n") end end

-- ^eqa$  ->  fire one EQ-lane attack using offense logic
Yso = Yso or {}
Yso.off = Yso.off or {}
Yso.off.oc = Yso.off.oc or {}
if type(Yso.off.oc.attack_eqonly) == "function" then
  Yso.off.oc.attack_eqonly()
else
  cecho("<red>[YSO]<reset> Offense module not loaded.\n")
end
